import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';
import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';

const ID_NAMED_REGION_PROVIDER = 'namedRegion';

export interface NamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

/**
 * Provider that detects and extracts named folding regions from #region/#endregion comments.
 * Supports formats like:
 * - // #region MyRegionName
 * - // #endregion
 * - /* #region MyRegionName */
 * - /* #endregion */
 */
export class NamedRegionProvider implements RangeProvider {
	readonly id = ID_NAMED_REGION_PROVIDER;

	private namedRegions: NamedRegion[] = [];

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter
	) { }

	dispose() { }

	compute(cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
		const regions = this.detectNamedRegions();
		return Promise.resolve(this.convertToFoldingRegions(regions));
	}

	/**
	 * Detects all named regions in the model.
	 * Returns an array of NamedRegion objects.
	 */
	private detectNamedRegions(): NamedRegion[] {
		const regions: NamedRegion[] = [];
		const stack: { name: string; startLineNumber: number }[] = [];

		const regionStartPattern = /^\s*(\/\/|\/\*)\s*#region\s*(.*?)\s*(\/\*)?\s*$/;
		const regionEndPattern = /^\s*(\/\/|\/\*)\s*#endregion\s*(\/\*)?\s*$/;

		for (let lineNumber = 1; lineNumber <= this.editorModel.getLineCount(); lineNumber++) {
			const lineContent = this.editorModel.getLineContent(lineNumber);

			const startMatch = lineContent.match(regionStartPattern);
			if (startMatch) {
				const regionName = startMatch[2] || 'Region';
				stack.push({ name: regionName.trim(), startLineNumber: lineNumber });
				continue;
			}

			const endMatch = lineContent.match(regionEndPattern);
			if (endMatch && stack.length > 0) {
				const startRegion = stack.pop()!;
				regions.push({
					name: startRegion.name,
					startLineNumber: startRegion.startLineNumber,
					endLineNumber: lineNumber
				});
			}
		}

		this.namedRegions = regions;
		return regions;
	}

	/**
	 * Converts detected named regions to FoldingRegions format.
	 */
	private convertToFoldingRegions(regions: NamedRegion[]): FoldingRegions | null {
		if (regions.length === 0) {
			return null;
		}

		const limit = this.foldingRangesLimit.limit;
		const regionsToUse = regions.length <= limit ? regions : regions.slice(0, limit);

		if (regionsToUse.length !== regions.length) {
			this.foldingRangesLimit.update(regions.length, limit);
		} else {
			this.foldingRangesLimit.update(regions.length, false);
		}

		const startIndexes = new Uint32Array(regionsToUse.length);
		const endIndexes = new Uint32Array(regionsToUse.length);
		const types: string[] = [];

		for (let i = 0; i < regionsToUse.length; i++) {
			const region = regionsToUse[i];
			if (region.startLineNumber > MAX_LINE_NUMBER || region.endLineNumber > MAX_LINE_NUMBER) {
				continue;
			}
			startIndexes[i] = region.startLineNumber;
			endIndexes[i] = region.endLineNumber;
			types[i] = region.name;
		}

		return new FoldingRegions(startIndexes, endIndexes, types);
	}

	/**
	 * Gets all named regions detected in the model.
	 */
	getNamedRegions(): NamedRegion[] {
		return this.namedRegions;
	}
}

